func solve(edges: Array<Array<Int64>>, online: Array<Bool>, k: Int64): Int64 {
    n = online.length
    BIG: Int64 = 1000000000000000000

    maxc: Int64 = 0
    if edges.length > 0 {
        for i in 0:edges.length {
            var edge = edges[i]
            if edge[2] > maxc {
                maxc = edge[2]
            }
        }
    }

    low: Int64 = 0
    high: Int64 = maxc

    while low <= high {
        mid: Int64 = (low + high) / 2
        var in_degree = Array<Int64>(n, 0)
        var adj = Array(n) { Array<Array<Int64>>::new() }

        for i in 0:edges.length {
            var edge = edges[i]
            u = edge[0]
            v = edge[1]
            cost = edge[2]
            if v == 0 {
                continue
            }
            if cost < mid {
                continue
            }
            if !online[u] || !online[v] {
                continue
            }
            adj[u].append([v, cost])
            in_degree[v] = in_degree[v] + 1
        }

        var dist = Array<Int64>(n, BIG)
        dist[0] = 0
        var q = Array<Int64>::new()
        var q_head: Int64 = 0
        for i in 0:n {
            if online[i] && in_degree[i] == 0 {
                q.push_back(i)
            }
        }

        while q_head < q.length {
            u = q[q_head]
            q_head += 1
            u_idx = u
            for j in 0:adj[u_idx].length {
                edge_info = adj[u_idx][j]
                v = edge_info[0]
                cost_edge = edge_info[1]
                v_idx = v
                new_dist = dist[u_idx] + cost_edge
                if new_dist < dist[v_idx] {
                    dist[v_idx] = new_dist
                }
                in_degree[v_idx] = in_degree[v_idx] - 1
                if in_degree[v_idx] == 0 {
                    q.push_back(v)
                }
            }
        }

        if dist[n-1] <= k {
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    if high < 0 {
        return -1
    } else {
        return high
    }
}
