            reverseGraph[v].append(Edge(target: u, cost: cost))
        }
    }

    var reachable0 = [Bool](repeating: false, count: n)
    var queue = [Int]()
    reachable0[0] = true
    queue.append(0)
    while !queue.isEmpty {
        let u = queue.removeFirst()
        for edge in forwardGraph[u] {
            let v = edge.target
            if !reachable0[v] {
                reachable0[v] = true
                queue.append(v)
            }
        }
    }

    if !reachable0[n-1] {
        return -1
    }

    var reachablen = [Bool](repeating: false, count: n)
    var queue2 = [Int]()
    reachablen[n-1] = true
    queue2.append(n-1)
    while !queue2.isEmpty {
        let u = queue2.removeFirst()
        for edge in reverseGraph[u] {
            let v = edge.target
            if !reachablen[v] {
                reachablen[v] = true
                queue2.append(v)
            }
        }
    }

    var reduced_node = [Bool](repeating: false, count: n)
    for i in 0..<n {
        if include_node[i] && reachable0[i] && reachablen[i] {
            reduced_node[i] = true
        }
    }

    if !reduced_node[0] || !reduced_node[n-1] {
        return -1
    }

    var reduced_edges = [Edge]()
    var graph_reduced_forward = Array(repeating: [Edge](), count: n)
    for u in 0..<n {
        if !reduced_node[u] { continue }
        for edge in forwardGraph[u] {
            let v = edge.target
            if reduced_node[v] {
                reduced_edges.append(edge)
                graph_reduced_forward[u].append(edge)
            }
        }
    }

    var in_degree = [Int](repeating: 0, count: n)
    for u in 0..<n {
        for edge in graph_reduced_forward[u] {
            let v = edge.target
            in_degree[v] += 1
        }
    }

    var topo_order = [Int]()
    var q = [Int]()
    for i in 0..<n {
        if reduced_node[i] && in_degree[i] == 0 {
            q.append(i)
        }
    }

    while !q.isEmpty {
        let u = q.removeFirst()
        topo_order.append(u)
        for edge in graph_reduced_forward[u] {
            let v = edge.target
            in_degree[v] -= 1
            if in_degree[v] == 0 {
                q.append(v)
            }
        }
    }

    var candidate_costs = Set<Int64>()
    for edge in reduced_edges {
        candidate_costs.insert(edge.cost)
    }
    let candidate_costs_sorted = candidate_costs.sorted()

    let INF: Int64 = 1000000000000000000
    var low_index = 0
    var high_index = candidate_costs_sorted.count - 1
    var result: Int64 = -1

    while low_index <= high_index {
        let mid_index = (low_index + high_index) / 2
        let candidate_x = candidate_costs_sorted[mid_index]
        var dp = [Int64](repeating: INF, count: n)
        dp[0] = 0
