import "std.cnja"

fn solve(edges: Array<Array<Int64>>, online: Array<Bool>, k: Int64): Int64 {
    let n: Int = online->len()
    mut allowed = Array<Bool>(length: n, value: false)
    for let i in range(0, n) {
        if i == 0 || i == n-1 || online->get(i) {
            allowed->set(i, true)
        }
    }

    mut max_edge: Int64 = 0
    for let edge in edges {
        let c: Int64 = edge->get(2)
        if c > max_edge {
            max_edge = c
        }
    }

    fn feasible(edges: Array<Array<Int64>>, n: Int, allowed: Array<Bool>, x: Int64, k: Int64): Bool {
        mut in_degree_count = Array<Int>(length: n, value: 0)
        mut graph_in = Array<Array<(Int, Int64)>>(length: n)
        mut graph_out = Array<Array<(Int, Int64)>>(length: n)

        for let i in range(0, n) {
            graph_in->set(i, Array<(Int, Int64)>->init())
            graph_out->set(i, Array<(Int, Int64)>->init())
        }

        for let edge in edges {
            let u: Int = edge->get(0)->to_int()
            let v: Int = edge->get(1)->to_int()
            let c: Int64 = edge->get(2)
            if v == 0 {
                continue
            }
            if c < x {
                continue
            }
            if not allowed->get(u) || not allowed->get(v) {
                continue
            }
            graph_out->get(u)->append((v, c))
            graph_in->get(v)->append((u, c))
            in_degree_count->set(v, in_degree_count->get(v) + 1)
        }

        mut dp = Array<Int64>(length: n, value: Int64->MAX)
        dp->set(0, 0)

        mut q = Array<Int>->init()
        for let i: Int in range(0, n) {
            if allowed->get(i) && in_degree_count->get(i) == 0 {
                q->append(i)
            }
        }

        mut idx_q: Int = 0
        while idx_q < q->len() {
            let u = q->get(idx_q)
            idx_q = idx_q + 1

            if u != 0 {
                var best: Int64 = Int64->MAX
                let parents = graph_in->get(u)
                for idx: Int in range(0, parents->len()) {
                    let (pu, pc) = parents->get(idx)
                    let cost_here: Int64 = dp->get(pu)
                    if cost_here == Int64->MAX {
                        continue
                    }
                    let candidate = cost_here + pc
                    if candidate < best {
                        best = candidate
                    }
