                dp->set(u, best)
            }

            let children = graph_out->get(u)
            for idx: Int in range(0, children->len()) {
                let (v, c_out) = children->get(idx)
                in_degree_count->set(v, in_degree_count->get(v) - 1)
                if in_degree_count->get(v) == 0 {
                    q->append(v)
                }
            }
        }

        let last_node: Int = n - 1
        return dp->get(last_node) <= k
    }

    mut ans: Int64 = -1
    mut low: Int64 = 0
    mut high: Int64 = max_edge

    while low <= high {
        let mid = (low + high) / 2
        if feasible(edges, n, allowed, mid, k) {
            ans = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return ans
}
